module lfsr_32bit(
    input clk,
    input rst_n,
    input en,
    output [31:0] lfsr_out
);

    reg [31:0] feedback_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            feedback_reg <= 32'h1; // Non-zero seed value
        end else if (en) begin
            feedback_reg <= {feedback_reg[30:0], feedback_reg[31] ^ feedback_reg[21] ^ feedback_reg[1] ^ feedback_reg[0]};
        end
    end

    assign lfsr_out = feedback_reg;

endmodule
